class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def plusOne(head: ListNode) -> ListNode:
    dummy = ListNode(0)
    dummy.next = head

    rightmost_non_nine = dummy
    current = head
    while current:
        if current.val != 9:
            rightmost_non_nine = current
        current = current.next

    rightmost_non_nine.val += 1

    current = rightmost_non_nine.next
    while current:
        current.val = 0
        current = current.next

    if dummy.val == 1:
        return dummy
    else:
        return dummy.next
